let minVsAvg = 3;
let persistTagged = true;
try {
  const whItems = $('Webhook 태깅').all();
  if (whItems.length) {
    const raw = whItems[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.minVsAvg != null) minVsAvg = Number(parsed.minVsAvg);
    if (parsed?.persistTagged != null) persistTagged = Boolean(parsed.persistTagged);
  }
} catch {
  /* manual / schedule defaults */
}
if (!Number.isFinite(minVsAvg) || minVsAvg <= 0) minVsAvg = 3;
return [{ json: { minVsAvg, persistTagged, source: 'n8n' } }];

const params = $('기준 설정').first().json;
const minVsAvg = params.minVsAvg;
const persistTagged = params.persistTagged;
const source = params.source || 'n8n';

const items = $input.all();
let rows = [];
const j0 = items[0]?.json;
if (items.length === 1 && Array.isArray(j0)) {
  rows = j0;
} else if (items.length >= 1 && j0 && typeof j0 === 'object' && !Array.isArray(j0) && j0.video_id) {
  rows = items.map((i) => i.json).filter((r) => r?.video_id);
} else if (items.length === 1 && j0 && Array.isArray(j0.data)) {
  rows = j0.data;
}

if (!rows.length) {
  return [{ json: {
    ok: true,
    minVsAvg,
    candidateCount: 0,
    taggedCount: 0,
    tierUpdatedCount: 0,
    message: `vs.Avg ${minVsAvg}x 이상 영상이 없습니다. YouTube 수집을 먼저 실행하세요.`,
    skipSave: true,
  } }];
}

const now = new Date().toISOString();
const tierRank = { C: 0, B: 1, A: 2, S: 3 };
const tierFor = (v) => (v >= 5 ? 'S' : v >= 3 ? 'A' : v >= 1.5 ? 'B' : 'C');

const tagRows = rows.map((v) => ({
  video_id: String(v.video_id),
  title: String(v.title || '').slice(0, 500),
  channel_id: v.channel_id ?? null,
  channel_name: v.channel_name ?? null,
  platform: v.platform || 'youtube',
  vs_avg: Number(v.vs_avg ?? 0),
  min_vs_avg_threshold: minVsAvg,
  tagged_at: now,
  source,
  updated_at: now,
}));

if (!persistTagged) {
  return [{ json: {
    ok: true,
    preview: true,
    minVsAvg,
    candidateCount: rows.length,
    taggedCount: 0,
    sample: tagRows.slice(0, 5),
    message: `미리보기: ${rows.length}개 후보`,
    skipSave: true,
  } }];
}

return [{ json: {
  ok: true,
  minVsAvg,
  candidateCount: rows.length,
  tagRows,
  skipSave: false,
} }];

const built = $('태그·Tier 목록 생성').first().json;
const count = (built.tagRows || []).length;
return [{ json: {
  ok: true,
  mode: 'n8n',
  minVsAvg: built.minVsAvg,
  candidateCount: built.candidateCount,
  taggedCount: count,
  tierUpdatedCount: 0,
  message: `아웃라이어 ${count}개 outlier_tags 저장 완료`,
  timestamp: new Date().toISOString(),
} }];

const built = $input.first().json;
return [{ json: {
  ok: built.ok !== false,
  mode: 'n8n',
  preview: built.preview === true,
  minVsAvg: built.minVsAvg,
  candidateCount: built.candidateCount ?? 0,
  taggedCount: built.taggedCount ?? 0,
  message: built.message,
  timestamp: new Date().toISOString(),
} }];
